css_snippet:
h1, h2, h3, h4, h5, h6 {
  text-wrap: balance;
  /* Add other desired typography styles */
  font-family: 'Inter', sans-serif;
  line-height: 1.2;
  letter-spacing: -0.02em;
}

/* For browsers that might not yet support it, though support is good */
@supports not (text-wrap: balance) {
  h1, h2, h3 {
    /* Consider alternative strategies or accept default wrapping */
    max-width: 60ch; /* Example fallback: limit width */
  }
}
